local OOOOOOOOO='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local function O000000O0(b)
    b=b:gsub('%s+','')
    b=b:gsub('[^'..OOOOOOOOO..'=]','')
    return (b:gsub('.', function(x)
        if x=='=' then return '' end
        local r,f='',(OOOOOOOOO:find(x,1,true)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0') end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
        if #x~=8 then return '' end
        local c=0
        for i=1,8 do if x:sub(i,i)=='1' then c=c+2^(8-i) end end
        return string.char(c)
    end))
end
local O00OO000O=O000000O0(O0OO0O000)
local O00O00OO0=(bit32 and bit32.bxor) or function(a,b) return a ~ b end
local OOOOOO0OO={}
for OOO00O00O=1,#O00OO000O do
    OOOOOO0OO[OOO00O00O]=string.char(O00O00OO0(O00OO000O:byte(OOO00O00O),O0OO0OO00))
end
